var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘! 요즘 수업 잘 나온다 싶더니 다시 지각이야?","JPN":"ナイエルちゃん！　最近サボり癖が治ったと思っていたら、また遅刻？","ENG":"Naielle! You're late! I thought you had made up your mind to come to class on time!","TWN":"奈爾！我才想說你最近都有準時上課，結果又遲到啦？"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시끄러! 늦게 일어났으니까 당연한 거잖아!","JPN":"うるさい！　寝坊したんだから仕方ないでしょ！？","ENG":"Shut it! I arrived late because I overslept!","TWN":"你好吵！睡過頭就會遲到，這不是正常的嗎！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"애초에 늦잠을 잤다는 소릴 당당하게 말하면 안 되지!","JPN":"そもそも寝坊したのってそんなに堂々と言えることじゃないからね！？","ENG":"You shouldn't be that confident about coming to school late because you overslept!","TWN":"睡過頭還敢這麼大聲！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"크읏- 애초에 넌 왜 나한테만 그렇게 엄격한 거야!","JPN":"くっ……いったいあんたはどうして私にそんな厳しいのよ！","ENG":"Kgh...! Why are you always so hard on me?!","TWN":"哼！你就只對我這麼嚴格！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"넌 타의 모범이 되어야 할 엘리트잖아! 널 닮고 싶어하는 애들이 얼마나 많은데!","JPN":"あなたはみんなのお手本になるべきエリートでしょ！　あなたの背中を見ている子たちがたくさんいるんだからね！","ENG":"Because you're an elite who should be a role model to the other students! Do you know how many students look up to you?","TWN":"你不是應該成為其他人學習的榜樣嗎？很多人都以你為目標欸！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 다른 녀석들이 이 엘리트님을 따르면 되는 거지. 뭐하러 굳이 내가 남의 눈치를 봐?","JPN":"ふん、このエリート様を見て学ぶのはみんなの勝手よ。どうして私が人の目を気にしないといけないのよ？","ENG":"Hmph! Then let them look up to me! But why do I have to walk on eggshells around them?","TWN":"哼，那他們就學我就好啦，我幹嘛要在意別人的眼光？"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아무튼 비켜! 점심시간엔 가야 할 데가 있으니까!","JPN":"とにかくどいて！　昼休憩中の用事もあるんだから！","ENG":"Whatever! Step out of the way! I have to be somewhere by lunch!","TWN":"你走開啦！我中午要去個地方！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 그건 뭐야? 도시락이 여러 개네?","JPN":"うん？　それは何？　どうしてそんなにお弁当箱を持ってるの？","ENG":"Hmm? What are those? Why do you have so many lunchboxes?","TWN":"嗯？那是什麼？怎麼這麼多便當？"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 신경 끄시지?","JPN":"ふん、あんたには関係ないでしょ！","ENG":"Hmph, mind your own business, will you?","TWN":"哼，不關你的事啦！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"설마 너, 도시락 준비하느라고 늦잠 잔 거야?","JPN":"もしかして、昨日の夜お弁当を用意してたから、寝坊しちゃったの？","ENG":"Were you... late to class because you were preparing all those lunches?","TWN":"你該不會是因為做便當才遲到的吧？"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"와아, 무슨 옛날 순정만화 주인공 같아.","JPN":"わあ、まるでひと昔前の少女漫画の主人公みたいだね。","ENG":"Wow! You're like one of those heroines from romance comics!","TWN":"哇，好像少女漫畫裡的女主角喔。"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"큿…!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"咳…！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"누구한테 주는 거야? 숨겨둔 남자친구?","JPN":"誰に渡すの？　内緒で付き合っている彼氏？","ENG":"Who's it for? A secret boyfriend you haven't told me about?","TWN":"你是要給誰的？你有男朋友喔？"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그런 거 없거든!","JPN":"そんなのいないわよ！","ENG":"I don't have a boyfriend!","TWN":"才沒有咧！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당분간 아카데미 밖으로 못 나오는 두 녀석이 원래 하던 일을 못 하니까, 대신 챙겨주는 것뿐이라고!","JPN":"あの二人、しばらくアカデミーから出られないから、代わりにやってるだけ！","ENG":"Since the two morons can't leave the Academy, I'm just stepping in to help them with their usual routines!","TWN":"因為他們二個暫時被禁足，我只是代替他們做他們原本在做的事而已啦！"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어그로와 블로킹이 원래 하던 일…?","JPN":"アグロとブロッキングのこと？","ENG":"Aggro and Block's usual routines?","TWN":"阿格洛和布洛京原本在做的事…？"},"stage":{"bg":"STREET_SPRING","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"외출 금지라고요?","JPN":"外出禁止ですか？","ENG":"They are grounded?","TWN":"禁足嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아이들과 잘 놀아주고 공부도 열심히 하던 학생들이었는데. 무슨 사고라도 친 건가요?","JPN":"子どもたちとよく遊んでくださって、勉強にも熱心な生徒だったのに、何か問題でも起こしたんでしょうか？","ENG":"What did they do? They were good students who got along with the kids and studied hard.","TWN":"他們和孩子們都相處得很好，也很認真念書，可以請問他們是犯什麼錯嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"가는 곳마다 자꾸 사고를 일으켜대서 잠깐 학교에 가둬놨어요.","JPN":"色んなところで問題ばかり起こすから、しばらくの間学校に閉じ込めておきました。","ENG":"They're banned from leaving school grounds because they kept causing trouble everywhere they went.","TWN":"因為他們在外面到處惹事生非，所以暫時被關在學校裡。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하하… 그래도 지금은 많이 반성하고 있으니까요.","JPN":"はは……でも、今はすごく反省しているみたいですよ。","ENG":"Haha... But at least they're reflecting on their mistakes.","TWN":"哈哈…但他們有在反省啦。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"번거로웠을 텐데, 이렇게 아이들 도시락을 챙겨 주셔서 감사합니다.","JPN":"すごく手間もかかったでしょうに、こうして子どもたちのお弁当まで用意してくださって、本当にありがとうございます。","ENG":"Making all these lunches for the children must have been troublesome for you. Thank you.","TWN":"謝謝你們還特地為孩子們準備便當，應該很麻煩你們吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"애들은 형들이 온다며 수요일 점심엔 끼니도 거르고 이것만 기다리거든요.","JPN":"子どもたちはいつも、お兄さんたちが来ると言って、水曜日はご飯を食べずに、ずっとこれを待っているんです。","ENG":"The kids would skip lunch on Wednesdays and wait for the boys to come with food.","TWN":"孩子們每週三都不吃午餐，就等哥哥們送便當來呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아이들에겐 어떻게 말씀하실 건가요?","JPN":"子どもたちにはどう伝えるおつもりですか？","ENG":"What are you going to tell the children?","TWN":"那我該怎麼跟孩子們解釋呢？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으음… 역시 아이들에겐 감기 때문에 쉬는 거라고 둘러대는 편이…","JPN":"うーん……やっぱり子どもたちには風邪で休んでいるって言った方が……","ENG":"Mmm... I think it's best to just tell them that they have a cold...","TWN":"嗯…就跟他們說哥哥們感冒…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그야 잘못을 지어서 죗값을 치르고 있다고 솔직히 말해야지!","JPN":"もちろん正直に、罪を償うためにしばらく来られないって言わなきゃでしょ！","ENG":"No, we have to tell them the truth! That they are doing time for their wrongdoings!","TWN":"當然就老實跟他們說，哥哥們做錯事被懲罰啊！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 바보들도 숨기지 말아달라고 했으니까.","JPN":"あのバカたちも隠さないでほしいって言っていたし。","ENG":"They even said that they didn't want to hide that from the kids.","TWN":"那二個笨蛋自己說要照實說的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"…그런 일이 있었구나.","JPN":"……そうだったんだ。","ENG":"...So that's what happened.","TWN":"…是喔。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"저기, 사실 형들이 그런 일을 하게 된 건… 나 때문일지도 몰라.","JPN":"その、お兄さんたちがそんなことをしたの……僕のせいかもしれない。","ENG":"Um, I think it's my fault... that they ended up like that.","TWN":"哥哥們會做出那種事…好像是我害的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 어째서?","JPN":"うん？　どうして？","ENG":"Hmm? How so?","TWN":"嗯？為什麼這麼說呢？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"나 카운터는 좀처럼 보기 힘드니까… 궁금해서 어떻게 카운터가 된 건지 물어봤었거든.","JPN":"僕、カウンターにはなかなか会えないから……気になっちゃって、どうやってカウンターになったのか聞いてみたんだ。","ENG":"It's rare to come across a Counter... so I asked how they became Counters.","TWN":"因為很難得可以看到制裁者…我就很好奇問哥哥們，怎麼樣才能成為制裁者。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"형들이 보육원에서 지낼 적에… 아이들이랑 유원지에 갔다가 침식사고를 겪었대.","JPN":"昔お兄さんたちがこの保育園に住んでいた頃……みんなで遊園地に行って、侵食事故に遭ったんだって。","ENG":"They told me that when they were at the orphanage... they went to an amusement park with the others but got caught in a Corruption accident.","TWN":"哥哥們說，他們也是在育幼院長大的…有一次大家一起去遊樂園，結果遇到侵蝕事件。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"그때 워치를 얻게 됐는데, 결국 친구는 지키지 못했댔어.","JPN":"その時、ウォッチを手に入れたけど、結局友達を守れなかったって言ってた。","ENG":"That's when they got their Watch, but they also told me that they couldn't save their friends.","TWN":"那時候雖然已經得到能量環，卻無法守護朋友。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"그래서 나… 형들한테 말했거든… 변두리에서 누가 카운터를 강하게 만드는 약을 팔고 있다더라고.","JPN":"だから僕……お兄さんたちに話したんだ……街外れで、カウンターを強化する薬を売ってる人がいるって。","ENG":"So, I... told them... that there's someone on the outskirts who sells potions that make Counters stronger.","TWN":"所以…我就跟哥哥們說…聽說郊區有人在賣可以讓制裁者變強的藥。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"괜히 말했어. 어차피 진짜인지도 모르는 소문이었는데.","JPN":"あんなの話すんじゃなかった。本当かどうかもわからないただの噂だったのに。","ENG":"I shouldn't have told them. It was just a rumor.","TWN":"我不應該跟哥哥們說的，因為這只是我聽說的，又不知道是不是真的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 일이 있었구나.","JPN":"そうだったんだ。","ENG":"I see.","TWN":"原來是這樣。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"고마워. 솔직하게 말해줘서.","JPN":"ありがとう、正直に話してくれて。","ENG":"Thank you for telling us the truth.","TWN":"謝謝你願意說實話。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"누나들… 나 때문에 형들이 곤경에 처한 거 맞지?","JPN":"お姉さんたち……僕のせいでお兄さんたちが辛い目に遭っているんだよね？","ENG":"Um... They are in trouble because of me, right?","TWN":"姊姊…是我害哥哥們被懲罰的吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그건 네 잘못이 아냐, 꼬맹이!","JPN":"あんたのせいじゃないわ、ガキ！","ENG":"It's not your fault, kid!","TWN":"小鬼，這不是你的錯！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우앗, 깜짝아.","JPN":"うわっ、びっくりした。","ENG":"Whoa!","TWN":"哇咧，想嚇死誰！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 녀석들이 아무리 단순무식하다지만 스스로 선택도 못하는 바보는 아니니까.","JPN":"あいつらは確かに単純バカだけど、物事の判断を自分でできないほどのバカじゃないよ。","ENG":"Those doofuses might be foolish and ignorant, but they're smart enough to make their own choices.","TWN":"他們雖然頭腦簡單，但還沒有笨到無法自己做出判斷的地步。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그러니까 넌 마음에 담아두지 말고, 그 녀석들이 돌아왔을 때 평소처럼 대해주면 돼! 알겠지?!","JPN":"だからあんたはあんまり気にしないで、あいつらが戻ってきたら、いつも通りに接してやればいいのよ、わかった！？","ENG":"So, don't blame yourself. When they come back, treat them like you always have! Got that?","TWN":"所以你也不需要把這件事放心上，等他們之後回來，就和平常一樣相處就好！知道嗎？！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"어… 으응…","JPN":"う……うん……","ENG":"Um... O-okay...","TWN":"喔…嗯嗯…"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아아- 그 녀석들 생각할수록 정말 멍청하네!","JPN":"あーあ、あいつらってやっぱり本当にバカよね。","ENG":"Agh...! Those two seem dumber the more I think about them!","TWN":"哀哀～越想越覺得他們很蠢！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"학교로 돌아가는대로 이 엘리트님이 제대로 지도해주겠어!","JPN":"学校に戻ったら、さっそくこのエリート様が指導してやるわ！","ENG":"As an elite, I'll teach them a lesson the second I get back to school!","TWN":"等回到學校後，我一定要好好指導他們！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"각오하라고 해! 강해지고 싶다면 허튼 마음을 먹는 게 아니라 오로지 노력만이 답이라는 걸!","JPN":"覚悟しなさい！　強くなりたければ、気持ちじゃなくて、努力するしか方法はないんだから！","ENG":"I'll show them! If they want to become stronger, the only way is to put in the effort and not cut any corners!","TWN":"覺悟吧！想要變強不是搞這些有的沒的，努力才是唯一個答案！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이 엘리트님께서 뼛속 깊이 새겨줄 테니까!","JPN":"このエリート様が骨の髄まで教え込んであげる！","ENG":"I, the elite, will engrave that deep into their thick skulls!","TWN":"我會把這句真理刻在他們的心板上的！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정말 데리고 다니기 피곤한 성격이라니까.","JPN":"本当に困った子だよね、ナイエルちゃんって。","ENG":"You are exhausting to hang out with.","TWN":"跟你一起出門真的很累。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"현장에 있던 자들은 일망타진했지만… 정작 타오는 완전히 종적을 감췄더군요.","JPN":"現場にいた者たちは全て倒しましたが……肝心のタオ本人は逃してしまいました。","ENG":"The others at the scene seem to have dispersed... However, Tao has completely hidden from us.","TWN":"雖然已經將現場的人都一網打盡…但還是沒找到浮士德的下落。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"미안하오. 본인의 준비가 미흡했던 탓에 그대의 오랜 계획 또한 어그러지고 말았으니.","JPN":"申し訳ありません。自分がしっかり準備しなかったせいで、貴殿の長年の計画を狂わせてしまいました。","ENG":"My apologies. Because of my lack of preparation, your years-long plan has been foiled.","TWN":"抱歉，因為在下準備得不周全，才會害你規劃已久的計畫失敗。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어쩔 수 없는 일이었습니다.","JPN":"仕方のないことでしたよ。","ENG":"It was inevitable.","TWN":"這也是沒辦法的事。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무고한 학생들이 인질로 잡혔었고, 저는 보안을 위해 시엘 양에게 제 목적을 숨기고 있었으니까요.","JPN":"罪のない生徒たちが人質に取られていましたし、私も秘密保守のために、シエルさんに自分の目的を隠していましたから。","ENG":"He had taken our students as hostages, and I had been hiding my objective from you for security reasons.","TWN":"因為他抓無辜的學生當人質，安全起見，我才沒有對希爾同學說。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그자가 감찰부의 존재를 의식한 이상, 이전보다 움직임이 더 조심스러워지겠구려.","JPN":"彼が観察部の存在を認知した以上、相手は今までより足跡を残さなくなるでしょう。","ENG":"Since he is now aware of the existence of the investigations department, he will be even more cautious with his actions.","TWN":"他知道有人在監視他後，之後行動恐怕只會更小心。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"大丈夫です。","ENG":"It is all right.","TWN":"沒關係。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금은 그자의 행적보다 저희 학생들이 무사한 것만으로 충분하니까요.","JPN":"今は彼がどこに消えたかより、アカデミーの生徒が無事だったことの方が重要ですから。","ENG":"I am more glad that our students are safe than worried about his whereabouts.","TWN":"最重要的是學生沒事就好，他的下落之後再說。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양의 상처는 잘 돌보고 있나요?","JPN":"シエルさんご自身のお怪我はいかがですか？","ENG":"How are your wounds, Ciel?","TWN":"希爾同學的傷勢恢復得還好嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"많이 호전되었소. 일상에는 지장이 없을 거라고 하오.","JPN":"だいぶ回復しました。日常生活には支障がないと言われています。","ENG":"It is getting better. I believe I will have no trouble handling everyday tasks.","TWN":"已經恢復許多，可以正常自理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미안해요.","JPN":"ごめんなさい。","ENG":"I am sorry.","TWN":"對不起。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"왜 사과를 하는지 모르겠구려.","JPN":"なぜ謝るのでしょう？","ENG":"I do not understand why you are apologizing.","TWN":"為何要跟在下道歉呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"회장은 위기에 몰린 본인을 구했을 뿐인데.","JPN":"会長は危機に陥った自分を助けてくれたではないですか。","ENG":"You saved me from danger.","TWN":"會長只是因為要救在下。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제 경솔했던 결정이 시엘 양을 상처 입힌 거나 마찬가지니까요.","JPN":"私の決断が軽率だったせいで、シエルさんにお怪我をさせてしまったようなものですから。","ENG":"My thoughtless decision is what got you hurt, Ciel.","TWN":"這等於是因為我的草率決定才會害希爾同學受傷的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제가 학생회장의 권한으로 처음부터 두 학생을 처벌했더라면, 애초에 이런 사고는 일어나지 않았겠죠.","JPN":"生徒会長として、最初から二人を処罰しておけば、そもそもこのような事故には発展しませんでした。","ENG":"If I had used my authority to punish those two from the beginning, then none of this would have happened.","TWN":"要是我一開始就行使學生會長的權力懲罰他們，就不會發生這種事了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"누구도 죄인에게 기회를 주지 않는다면, 본인 또한 이 자리에 있지는 못했을 거요.","JPN":"罪を犯した人間にチャンスを与える者が誰もいなければ、自分だって今この場にいられなかったでしょう。","ENG":"If no one is given a second chance, then I would not be here either.","TWN":"要是沒有人願意給犯錯的人機會，那在下也不會站在這裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 결정이 옳았는지 틀렸는지는… 끝까지 가보지 않으면 모르는 것이지.","JPN":"その決断が正しかったかどうかは……最後まで結果を見てみなければわかりません。","ENG":"We will not know if your decision was right or wrong... until we see the end of it.","TWN":"那個決定到底是對或錯…唯有走到最後才會知道。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇게 말하는 시엘 양은… 어른스러운 사람이네요.","JPN":"そう言えるシエルさんは……大人ですね。","ENG":"It is very... mature of you, to talk like that, Ciel.","TWN":"希爾同學說出這種話…感覺好像大人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"음지에서 길러진 한낱 암살자일 뿐이라오.","JPN":"自分は暗部で育てられた、ただの暗殺者ですよ。","ENG":"I am a mere assassin, molded from darkness.","TWN":"在下只是黑暗組織培育出來的一名刺客而已。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대가 백서의 사람이라면, 본인의 정체도 진즉 알고 있었겠지만.","JPN":"貴殿が白西の者ということは、自分の正体にもとっくに気づいていたはずですが？","ENG":"But, as a member of White West, you would have already known who I was.","TWN":"若你是白西的人，那應該早就知道在下的真實身分。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"알고 있었어요. 시엘 양이 이곳에 온 첫날, 제가 가진 검조각이 반응했으니까요.","JPN":"はい。シエルさんがここに来た初日、私の剣の欠片が反応しましたから。","ENG":"I did. When you first arrived at this place, my shard quivered.","TWN":"我知道，因為你來的第一天，我身上的干將碎片就有反應。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇다면 어째서 한 번도 본인과 싸우려 하지 않은 거요?","JPN":"なら、どうして一度も自分と戦おうとしなかったのです？","ENG":"Then, why did you not challenge me to battle?","TWN":"那你為何從未找在下決鬥呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"백서의 문주는 많은 것을 책임지게 되는 직책이죠.","JPN":"白西の門主は多くを抱えなければならない立場です。","ENG":"The leader of White West must take on serious responsibilities.","TWN":"因為白西幫主的責任重大。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지부 재정과 인적자원의 관리, 민심, 그리고 판단에 따라 갈리는 사람 목숨이 걸린 일들까지…","JPN":"支部の財政管理と、人的資源のマネジメント、民心の管理、それに人の命を左右する出来事に対する判断責任まで。","ENG":"Managing finances, human resources, the public, and, depending on the situation, the fate of a person's life.","TWN":"不只要管理財務、人力、民心，而且你的決定牽一髮而動全身…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 그 모든 것들을 책임지기엔, 아직 배움이 필요한 학생일 뿐입니다.","JPN":"私はまだ、その全てが背負いきれるような人間ではありません。学びが必要な生徒なんです。","ENG":"But I am just a student in learning. I cannot take on such responsibilities at the moment.","TWN":"但我只是個學生，還有許多要學習的地方，才能背負如此重責大任。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대가 생각하기에, 본인은 배움이 필요하다고 생각하오?","JPN":"貴殿から見て、自分は学ぶ必要があると思いますか？","ENG":"Do you truly think that you need more learning?","TWN":"你認為在下也還需要學習嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"배움은 누군가의 강요로 얻는 것이 아닙니다.","JPN":"学びは他人に強いられるものではありません。","ENG":"Learning is not obtained through someone's compulsion.","TWN":"學習這件事不應該是由別人來勉強你。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"중요한 건, 시엘 양이 진정으로 그것을 필요로 하느냐에 달렸죠.","JPN":"大事なのは、シエルさん自身が本当にそれを必要としているかどうかです。","ENG":"What is important is whether you truly feel the necessity for it.","TWN":"而是取決於你認真覺得你需要嗎？這才是重點。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"케이크, 더 드시겠어요?","JPN":"ケーキ、もっと出しましょうか？","ENG":"Would you like some more cake?","TWN":"再來點蛋糕嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대가 권한다면, 기꺼이 부탁하리다.","JPN":"お言葉に甘えて、ぜひお願いします。","ENG":"If you are offering, I will not refuse.","TWN":"既然你都開口問了，那在下就不客氣了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"옌.","JPN":"イェン。","ENG":"Yen.","TWN":"嫣杏。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"생각해보면, 이름으로 불리는 건 꽤 간만이네요.","JPN":"そういえば、名前で呼ばれるのはすごく久しぶりなようですね。","ENG":"Come to think of it, it has been a while since someone called me by my name.","TWN":"現在想想，已經好久沒有人叫我的名字呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"앞으로는 어떻게 할 계획이죠?","JPN":"これからはどうするおつもりですか？","ENG":"What do you plan on doing from now on?","TWN":"你之後有什麼打算？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아카데미에 남아 더 많은 것을 배우고 싶소.","JPN":"アカデミーに残り、もっとたくさんのことを学びたいと思っています。","ENG":"I would like to stay at the Academy and learn.","TWN":"在下想留在學院繼續學習。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 시엘 양에겐 다른 도전자와 싸울 의무가 있지 않았나요?","JPN":"でも、シエルさんには、他の挑戦者と戦う義務があるのでは？","ENG":"What about your duty to battle the other challengers?","TWN":"但你不是有義務要和其他挑戰者決鬥嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인이 가장 싸우고 싶은 상대는 그대라오.","JPN":"自分が最も戦いたい相手は、貴殿ですよ。","ENG":"The person I would like to fight the most is you.","TWN":"在下最想決鬥的對象是你。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대를 처음 본 순간, 그대가 도전자가 되어주었으면 했소.","JPN":"ひと目見たときから、貴殿からの挑戦を心待ちにしているんです。","ENG":"Since the moment I met you, I was hoping you would challenge me.","TWN":"打從第一次見到你，在下就希望你可以當挑戰者。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"지금 당장이 아니라도 괜찮다오.","JPN":"今すぐじゃなくても、構いません。","ENG":"It does not have to be right now.","TWN":"不是非要現在，"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대가 문주의 책임을 짊어질 준비가 되었을 때, 백서의 도전자가 되어주었으면 하오.","JPN":"貴殿が門主としての責任を全うできると判断したとき、白西の挑戦者になってほしいと思っています。","ENG":"I wish you to challenge me when you are ready to wield the responsibility of sect leader.","TWN":"而是等你準備好要承擔幫主的責任時，希望你可以成為白西的挑戰者。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회에서는 항상 새로운 선도위원을 모집하고 있어요.","JPN":"生徒会は新しい風紀委員を常時募集しています。","ENG":"The Student Council is always recruiting new Student Guides.","TWN":"學生會常常在招募新的風紀委員。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 후보가 되어준다면, 저도 시엘 양의 제안을 받아들이도록 하죠.","JPN":"シエルさんに候補者になっていただけるのでしたら、こちらもシエルさんの提案を受け入れます。","ENG":"If you become a candidate, I shall accept your proposal.","TWN":"你願意加入的話，我也會同意你的提議。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그건… 모종의 거래인 거요?","JPN":"それは……一種の取引のようなものでしょうか？","ENG":"Is this... a deal you are suggesting?","TWN":"這算是…一種交易嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이 제안을 승낙한다면 졸업 전에는 시엘 양에게 도전하겠습니다.","JPN":"この提案を受け入れてくださるなら、卒業までにシエルさんに挑戦しましょう。","ENG":"If you accept this proposal, then I shall challenge you before I graduate.","TWN":"你同意的話，在畢業前我會向你下戰帖的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아카데미의 귀감이 되려면, 앞으로 배워야 할 것이 많겠구려.","JPN":"アカデミーのお手本となるには、これからたくさんの学びが必要になります。","ENG":"To become a model in the Academy, it seems that I have much to learn.","TWN":"要想成為學院的榜樣，往後還有許多需要學習的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"무지한 본인을 가르치는 것은 쉽지 않을 거요.","JPN":"無知な自分を教えるのは、きっと骨が折れるでしょう。","ENG":"It will not be easy teaching someone as ignorant as me.","TWN":"但在下愚昧，要教在下會有點辛苦。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…맡겨주세요.","JPN":"……任せてください。","ENG":"...Leave it to me.","TWN":"…包在我身上。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 기본적인 교칙부터, 교내 풍기를 관리하는 법까지 모두 가르쳐드리죠.","JPN":"アカデミーの基礎的なルールから、校内の風紀を管理する方法まで、全て伝授します。","ENG":"I will teach you everything, from basic school rules and etiquette to managing students.","TWN":"不管是學院的校規，還是校內風氣管理，這些我全都會教你。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"졸립구려.","JPN":"少し眠くなってきました。","ENG":"I feel tired.","TWN":"好睏。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"한숨 푹 주무세요.","JPN":"ゆっくり休んでください。","ENG":"Rest for now.","TWN":"好好睡一覺吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"배움은 밤낮을 가리지 않으니까.","JPN":"学びは昼夜を問いませんから。","ENG":"For there is no wrong time for learning.","TWN":"學習是不分白天晚上的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"본인은 사람을 죽이는 암살자요.","JPN":"自分は人殺しの暗殺者です。","ENG":"I am an assassin.","TWN":"在下是取人性命的刺客。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"암살자에겐 암살자만의 규율이 있고, 그것은 그대들이 살아가는 평화로운 일상의 법도와 결코 융화될 수 없다오.","JPN":"暗殺者には暗殺者が従うべき規律があり、それは貴殿らの生きる平和な日常のそれとは決して相容れないものなのです。","ENG":"Assassins have their own creed, which cannot be assimilated into the peaceful lives of many.","TWN":"刺客有刺客獨有的規則，這些規則絕對無法與你們平靜的日常生活法則融合。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"허나 그럼에도…","JPN":"ですが……","ENG":"Nevertheless...","TWN":"但即便如此…"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"이곳에서 많은 것을 배우고 싶어졌소.","JPN":"私はここで、もっと色々なことを学びたくなりました。","ENG":"It has come to my realization that there is much to learn from here.","TWN":"在下想在這裡學習更多的事物。"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"그대들이 본인의 이름을 불렀을 때, 이 가슴에 스며든 따스한 온기는 어떤 것인지.","JPN":"貴殿らに自分の名前を呼ばれたとき、胸が熱くなるこの感情は何なのでしょう。","ENG":"What the warmth I felt in my heart when you called my name is.","TWN":"當你們呼喊在下的名字時，注入心裡的暖流是什麼回事？"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 따스함을 지키기 위해 무엇을 할 수 있는지.","JPN":"その感情を失くさないためには、どうすれば良いのでしょう。","ENG":"What I have to do to keep this warmth.","TWN":"又該做些什麼才能守護這股暖流？"},"stage":{"bg":"CLAN_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"그 모든 것을 배우고 난 뒤엔…","JPN":"そして全てを学び終わったあとは……","ENG":"After I have learned all of those things...","TWN":"等這些全都學會後…"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"고향으로 돌아가, 사부님의 이름을 찾아보고 싶구려.","JPN":"故郷に戻り、師匠の名前を調べてみたいです。","ENG":"I would like to return home and look for my master's name.","TWN":"我會回到老家，因為我想尋找師父的名字。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};